#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100005

// Define the structure for a tree node
typedef struct Node {
    int value;
    int parent;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int value, int parent) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->parent = parent;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to update the subtree rooted at a node
void updateSubtree(Node* node, int k) {
    node->value = (node->value + fib(k)) % MOD;
    for (int i = 0; i < node->numChildren; i++) {
        updateSubtree(node->children[i], k + 1);
    }
}

// Function to calculate the kth Fibonacci number
int fib(int k) {
    if (k <= 2) return 1;
    int a = 1, b = 1;
    for (int i = 3; i <= k; i++) {
        int temp = a;
        a = b;
        b = (temp + b) % MOD;
    }
    return b;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Node** nodes = (Node**)malloc(N * sizeof(Node*));
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(0, -1);
    }
    for (int i = 1; i < N; i++) {
        int parent;
        scanf("%d", &parent);
        nodes[i]->parent = parent - 1;
        addChild(nodes[parent - 1], nodes[i]);
    }
    for (int i = 0; i < M; i++) {
        char query[3];
        scanf("%s", query);
        if (query[0] == 'Q') {
            int node;
            scanf("%d", &node);
            printf("%d\n", nodes[node - 1]->value);
        } else {
            int node, k;
            scanf("%d %d", &node, &k);
            updateSubtree(nodes[node - 1], k);
        }
    }
    return 0;
}

