import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 100005;

    // Define the structure for a tree node
    static class Node {
        int value;
        int parent;
        ArrayList<Node> children;

        public Node(int value, int parent) {
            this.value = value;
            this.parent = parent;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to update the subtree rooted at a node
    static void updateSubtree(Node node, int k) {
        node.value = (node.value + fib(k)) % MOD;
        for (Node child : node.children) {
            updateSubtree(child, k + 1);
        }
    }

    // Function to calculate the kth Fibonacci number
    static int fib(int k) {
        if (k <= 2) return 1;
        int a = 1, b = 1;
        for (int i = 3; i <= k; i++) {
            int temp = a;
            a = b;
            b = (temp + b) % MOD;
        }
        return b;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(0, -1);
        }
        for (int i = 1; i < N; i++) {
            int parent = scanner.nextInt();
            nodes[i].parent = parent - 1;
            addChild(nodes[parent - 1], nodes[i]);
        }
        for (int i = 0; i < M; i++) {
            String query = scanner.next();
            if (query.equals("Q")) {
                int node = scanner.nextInt();
                System.out.println(nodes[node - 1].value);
            } else {
                int node = scanner.nextInt();
                int k = scanner.nextInt();
                updateSubtree(nodes[node - 1], k);
            }
        }
    }
}

